@@ -6,6 +6,121 @@ export interface ResolvedProcessor {
   config: ProcessorRuntimeConfig;
 }

+function compareConfigs(left: ProcessorRuntimeConfig, right: ProcessorRuntimeConfig) {
+  if (left.order !== right.order) {
+    return left.order - right.order;
+  }
+
+  return left.id.localeCompare(right.id);
+}
+
+function mergeConfig(config: ProcessorRuntimeConfig, override?: ProcessorOverride): ProcessorRuntimeConfig {
+  return {
+    ...config,
+    enabled: override?.enabled ?? config.enabled,
+    options: {
+      ...config.options,
+      ...(override?.options ?? {}),
+    },
+  };
+}
+
+export function resolveProcessorGraph(
+  processors: ReadonlyMap<string, Processor>,
+  configs: Iterable<ProcessorRuntimeConfig>,
+  overrides: Record<string, ProcessorOverride> = {},
+): ResolvedProcessor[] {
+  const resolvedConfigs = new Map<string, ProcessorRuntimeConfig>();
+
+  for (const config of configs) {
+    resolvedConfigs.set(config.id, mergeConfig(config, overrides[config.id]));
+  }
+
+  const activeConfigs = Array.from(resolvedConfigs.values())
+    .filter((config) => config.enabled)
+    .sort(compareConfigs);
+  const activeIds = new Set(activeConfigs.map((config) => config.id));
+  const dependents = new Map<string, string[]>();
+  const inDegree = new Map<string, number>();
+
+  for (const config of activeConfigs) {
+    const processor = processors.get(config.id);
+    if (!processor) {
+      throw new Error(`Processor ${config.id} is not available.`);
+    }
+
+    inDegree.set(config.id, 0);
+    dependents.set(config.id, []);
+  }
+
+  for (const config of activeConfigs) {
+    for (const dependencyId of config.dependencyIds) {
+      if (dependencyId === config.id) {
+        throw new Error(`Circular dependency detected for processor ${config.id}.`);
+      }
+
+      const dependencyConfig = resolvedConfigs.get(dependencyId);
+      if (!dependencyConfig) {
+        throw new Error(`Processor ${config.id} dependency ${dependencyId} is missing.`);
+      }
+
+      if (!dependencyConfig.enabled || !activeIds.has(dependencyId)) {
+        throw new Error(`Processor ${config.id} dependency ${dependencyId} is disabled or not available.`);
+      }
+
+      if (!processors.has(dependencyId)) {
+        throw new Error(`Processor ${config.id} dependency ${dependencyId} is not available.`);
+      }
+
+      dependents.get(dependencyId)?.push(config.id);
+      inDegree.set(config.id, (inDegree.get(config.id) ?? 0) + 1);
+    }
+  }
+
+  const queue = activeConfigs
+    .filter((config) => (inDegree.get(config.id) ?? 0) === 0)
+    .sort(compareConfigs);
+  const resolved: ResolvedProcessor[] = [];
+
+  while (queue.length > 0) {
+    const currentConfig = queue.shift();
+    if (!currentConfig) {
+      break;
+    }
+
+    const processor = processors.get(currentConfig.id);
+    if (!processor) {
+      throw new Error(`Processor ${currentConfig.id} is not available.`);
+    }
+
+    resolved.push({
+      processor,
+      config: currentConfig,
+    });
+
+    for (const dependentId of dependents.get(currentConfig.id) ?? []) {
+      const nextDegree = (inDegree.get(dependentId) ?? 0) - 1;
+      inDegree.set(dependentId, nextDegree);
+      if (nextDegree === 0) {
+        const dependentConfig = resolvedConfigs.get(dependentId);
+        if (dependentConfig?.enabled) {
+          queue.push(dependentConfig);
+          queue.sort(compareConfigs);
+        }
+      }
+    }
+  }
+
+  if (resolved.length !== activeConfigs.length) {
+    const unresolvedIds = activeConfigs
+      .map((config) => config.id)
+      .filter((id) => !resolved.some((entry) => entry.config.id === id));
+    throw new Error(`Circular dependency detected: ${unresolvedIds.join(', ')}`);
+  }
+
+  return resolved;
+}
